// Pass 8 v1.6 UI — accessible settings, dialogue history and performance report.
const A11Y_UI_VERSION='1.6.0';
function a11yVolumeRow(labelText,key,y,color){const value=Math.round(game.settings[key]*100);text(labelText,115,y+20,14,COLORS.paper,true);addButton(355,y,42,28,'−',()=>{game.settings[key]=clamp(game.settings[key]-.1,0,1);a11yPersist();},true,false,color);uiGlass(410,y,300,28,8,.72);ctx.fillStyle=color;uiRoundedPath(416,y+6,Math.max(2,288*game.settings[key]),16,6);ctx.fill();centeredAt(`${value}%`,560,y+20,11,COLORS.paper,`bold 11px ${UI_FONT}`);addButton(723,y,42,28,'+',()=>{game.settings[key]=clamp(game.settings[key]+.1,0,1);a11yPersist();audio.click();},true,false,color);}
function a11yToggle(x,y,w,labelText,key,color=COLORS.blue){addButton(x,y,w,31,`${labelText}: ${game.settings[key]?'ON':'OFF'}`,()=>{if(key==='masterMute'){audio.toggle();return;}game.settings[key]=!game.settings[key];a11yPersist();a11yAnnounce(`${labelText} ${game.settings[key]?'on':'off'}.`);},true,game.settings[key],color);}
function a11yCycle(key,values){const index=values.indexOf(game.settings[key]);game.settings[key]=values[(index+1)%values.length];a11yPersist();}
function openAccessibility(page=0){a11yEnsure();game.overlay={type:'accessibility',title:'Accessibility, Audio & Controls',page,listening:null};a11yAnnounce('Accessibility, audio and controls menu opened.');}
function drawAccessibilityOverlay(o){overlayBase(o.title);const tabs=['AUDIO','READING','VISUAL','CONTROLS'];tabs.forEach((labelText,index)=>addButton(92+index*195,92,178,28,labelText,()=>{o.page=index;o.listening=null;},true,o.page===index,COMMERCIAL_UI.ink2));if(o.page===0){a11yToggle(115,140,650,'MASTER MUTE','masterMute',COLORS.rose);a11yVolumeRow('Music volume','musicVolume',195,COMMERCIAL_UI.gold);a11yVolumeRow('Effects volume','effectsVolume',245,COMMERCIAL_UI.sky);a11yVolumeRow('Dialogue voice','dialogueVolume',295,COMMERCIAL_UI.rose);wrapped('All audio is original Web Audio synthesis. Muting never hides gameplay information: bells, warnings and results also use words, icons and status labels.',115,360,650,13,COLORS.cream,4);addButton(335,423,290,34,'PLAY AUDIO TEST',()=>{audio.bell();setTimeout(()=>audio.message(),350);setTimeout(()=>audio.good(),700);},true,false,COMMERCIAL_UI.gold);}else if(o.page===1){addButton(115,145,650,34,`TEXT SPEED: ${String(game.settings.textSpeed).toUpperCase()}`,()=>a11yCycle('textSpeed',['slow','normal','fast','instant']),true,false,COMMERCIAL_UI.sky);a11yToggle(115,197,310,'AUTO-ADVANCE','autoAdvance',COMMERCIAL_UI.mint);a11yToggle(455,197,310,'SKIP READ','skipRead',COMMERCIAL_UI.gold);a11yToggle(115,245,310,'SCREEN READER','screenReader',COMMERCIAL_UI.rose);addButton(455,245,310,34,`DIALOGUE HISTORY (${game.dialogueHistory.length})`,openDialogueHistory,true,false,COMMERCIAL_UI.navy);wrapped('Auto-advance is restricted to single safe continuations. Skip-read instantly reveals dialogue already completed on this device. The latest 80 conversations remain available in the save.',115,310,650,14,COLORS.cream,5);}else if(o.page===2){a11yToggle(115,145,310,'LARGE TEXT','largeText',COMMERCIAL_UI.sky);a11yToggle(455,145,310,'HIGH CONTRAST','highContrast',COMMERCIAL_UI.gold);a11yToggle(115,195,310,'REDUCED MOTION','reducedMotion',COMMERCIAL_UI.mint);a11yToggle(455,195,310,'AUTO LOW-POWER','autoPerformance',COMMERCIAL_UI.rose);addButton(115,247,310,34,`LOW-POWER MODE: ${game.settings.performanceMode?'ON':'OFF'}`,()=>{game.settings.performanceMode=!game.settings.performanceMode;a11yPersist();},true,game.settings.performanceMode,COMMERCIAL_UI.navy);addButton(455,247,310,34,'PERFORMANCE REPORT',openPerformanceReport,true,false,COMMERCIAL_UI.navy);wrapped('High contrast strengthens outlines and textual cues. Reduced motion removes rapid effects. Automatic low-power mode activates only after sustained slow frames and preserves all gameplay.',115,320,650,14,COLORS.cream,5);}else{addButton(115,140,310,32,`TOUCH SIZE: ${String(game.settings.touchScale).toUpperCase()}`,()=>a11yCycle('touchScale',['small','medium','large']),true,false,COMMERCIAL_UI.sky);a11yToggle(455,140,310,'GAMEPAD','gamepad',COMMERCIAL_UI.mint);const actions=['up','down','left','right','interact','options','history','map','room'];actions.forEach((action,index)=>{const col=index%3,row=Math.floor(index/3),x=115+col*220,y=195+row*58;addButton(x,y,200,34,o.listening===action?'PRESS A KEY…':`${action.toUpperCase()}: ${String(game.settings.controlMap[action]).toUpperCase()}`,()=>{o.listening=action;},true,o.listening===action,COMMERCIAL_UI.ink2);});addButton(335,386,290,31,'RESET DEFAULT CONTROLS',()=>{game.settings.controlMap={...A11Y_DEFAULT_CONTROLS};o.listening=null;a11yPersist();},true,false,COMMERCIAL_UI.rose);}addButton(365,467,230,32,'CLOSE',()=>{game.overlay=null;a11yPersist();});}
function openDialogueHistory(){game.overlay={type:'dialogueHistory',title:'Dialogue History',page:0};a11yAnnounce('Dialogue history opened.');}
function drawDialogueHistory(o){overlayBase(o.title);const history=[...game.dialogueHistory].reverse(),pageSize=5,page=clamp(o.page||0,0,Math.max(0,Math.ceil(history.length/pageSize)-1)),visible=history.slice(page*pageSize,page*pageSize+pageSize);text(`${history.length} saved conversations • newest first`,94,106,12,COLORS.sky,true);if(!visible.length)centered('No dialogue has been recorded yet.',270,18,COLORS.cream,`bold 18px ${UI_FONT}`);visible.forEach((entry,index)=>{const y=124+index*66;uiGlass(88,y,784,58,8,.72);text(entry.speaker,102,y+17,12,COLORS.gold,true);wrapped(entry.text.replace(/\s+/g,' '),102,y+36,748,10,COLORS.paper,1);if(entry.result)text(`↳ ${entry.result.slice(0,112)}`,102,y+53,9,COLORS.mint,true);});addButton(210,467,130,30,'PREVIOUS',()=>o.page=Math.max(0,page-1),page>0);addButton(365,467,230,30,'CLOSE',()=>game.overlay=null);addButton(620,467,130,30,'NEXT',()=>o.page=Math.min(Math.max(0,Math.ceil(history.length/pageSize)-1),page+1),page<Math.ceil(history.length/pageSize)-1);}
function openPerformanceReport(){game.overlay={type:'performanceReport',title:'Performance Report'};}
function drawPerformanceReport(){overlayBase('Performance Report');const stats=game.performanceStats||{averageMs:0,fps:0,samples:0,longFrames:0};uiGlass(110,125,740,245,15,.78);centered(`${Math.round(stats.fps||0)} FPS`,185,42,(stats.fps||60)>=50?COLORS.mint:(stats.fps||60)>=30?COLORS.gold:COLORS.rose,`bold 42px ${UI_FONT}`);text('Average frame time',165,235,14,COLORS.cream,true);text(`${Number(stats.averageMs||0).toFixed(1)} ms`,650,235,16,COLORS.paper,true);text('Frames in rolling sample',165,275,14,COLORS.cream,true);text(String(stats.samples||0),650,275,16,COLORS.paper,true);text('Long frames since launch',165,315,14,COLORS.cream,true);text(String(stats.longFrames||0),650,315,16,COLORS.paper,true);text('Low-power rendering',165,355,14,COLORS.cream,true);text(game.settings.performanceMode?'ACTIVE':'OFF',650,355,16,game.settings.performanceMode?COLORS.gold:COLORS.mint,true);wrapped('The monitor is local and sends no analytics. Automatic low-power mode reduces decorative weather and ambient audio while retaining readable UI and complete gameplay.',150,405,660,13,COLORS.cream,4);addButton(365,467,230,32,'BACK',()=>openAccessibility(2));}
const a11yUiBaseOverlay=drawOverlay;drawOverlay=function(){if(game.overlay?.type==='dialogueHistory'){ctx.fillStyle='rgba(9,11,18,.88)';ctx.fillRect(0,0,W,H);drawDialogueHistory(game.overlay);}else if(game.overlay?.type==='performanceReport'){ctx.fillStyle='rgba(9,11,18,.88)';ctx.fillRect(0,0,W,H);drawPerformanceReport();}else a11yUiBaseOverlay();};
function validateAccessibilityUI(){const issues=[];if(typeof openAccessibility!=='function'||typeof drawAccessibilityOverlay!=='function')issues.push('Accessibility menu is unavailable.');if(typeof openDialogueHistory!=='function'||typeof drawDialogueHistory!=='function')issues.push('Dialogue history is unavailable.');if(typeof openPerformanceReport!=='function')issues.push('Performance report is unavailable.');return{valid:issues.length===0,issues,version:A11Y_UI_VERSION,pages:4,dialogueHistory:true,performanceReport:true,remappingUI:true,colorIndependentLabels:true};}
